#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int* A = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < M; i++) {
        int G, x, y;
        scanf("%d %d %d", &G, &x, &y);
        int max = -1, count = 0;
        for (int j = x - 1; j < y; j++) {
            if (gcd(G, A[j]) > 1) {
                if (A[j] > max) {
                    max = A[j];
                    count = 1;
                } else if (A[j] == max) {
                    count++;
                }
            }
        }
        if (max == -1) {
            printf("-1 -1\n");
        } else {
            printf("%d %d\n", max, count);
        }
    }
    free(A);
    return 0;
}

