import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < M; i++) {
            int G = sc.nextInt();
            int x = sc.nextInt();
            int y = sc.nextInt();
            int max = -1, count = 0;
            for (int j = x - 1; j < y; j++) {
                if (gcd(G, A[j]) > 1) {
                    if (A[j] > max) {
                        max = A[j];
                        count = 1;
                    } else if (A[j] == max) {
                        count++;
                    }
                }
            }
            if (max == -1) {
                System.out.println("-1 -1");
            } else {
                System.out.println(max + " " + count);
            }
        }
    }
}

